using UnityEngine;

public class PlayerImmunity : MonoBehaviour
{
    public float duration = 5f;
    public Color auraColor = new Color(0f, 0.8f, 1f, 0.6f);
    public float auraScale = 2.5f;

    float timer;
    bool isActive;
    GameObject aura;
    StatusUI statusUI;

    void Awake()
    {
        statusUI = FindObjectOfType<StatusUI>();
        CreateAura();
    }

    public void Activate()
    {
        timer = duration;
        isActive = true;

        if (statusUI != null)
            statusUI.pauseDepletion = true;

        if (aura != null)
            aura.SetActive(true);
    }

    void Update()
    {
        if (!isActive) return;

        timer -= Time.deltaTime;
        if (timer <= 0f)
            Deactivate();
    }

    void Deactivate()
    {
        isActive = false;
        if (statusUI != null)
            statusUI.pauseDepletion = false;
        if (aura != null)
            aura.SetActive(false);
    }

    float pulseTimer;

    void CreateAura()
    {
        aura = new GameObject("ImmunityAura");
        aura.transform.SetParent(transform, false);
        aura.transform.localPosition = Vector3.zero;

        var sr = aura.AddComponent<SpriteRenderer>();
        sr.sprite = GenerateAuraSprite();
        sr.color = auraColor;
        sr.sortingOrder = -1;

        aura.transform.localScale = Vector3.one * auraScale;
        aura.SetActive(false);
    }

    void LateUpdate()
    {
        if (!isActive || aura == null) return;

        pulseTimer += Time.deltaTime * 3f;
        float pulse = Mathf.Sin(pulseTimer) * 0.15f + 1f;
        aura.transform.localScale = Vector3.one * auraScale * pulse;
    }

    Sprite GenerateAuraSprite()
    {
        int size = 128;
        var tex = new Texture2D(size, size, TextureFormat.RGBA32, false);
        float half = size * 0.5f;
        Color32[] pixels = new Color32[size * size];
        for (int y = 0; y < size; y++)
        {
            for (int x = 0; x < size; x++)
            {
                float dx = (x - half) / half;
                float dy = (y - half) / half;
                float dist = Mathf.Sqrt(dx * dx + dy * dy);

                // Outer bright ring (sharp edge)
                float outerRing = 1f - Mathf.Abs(dist - 0.92f) / 0.05f;
                outerRing = Mathf.Clamp01(outerRing);

                // Inner glow ring
                float innerRing = 1f - Mathf.Abs(dist - 0.75f) / 0.12f;
                innerRing = Mathf.Clamp01(innerRing) * 0.5f;

                // Soft fill
                float fill = Mathf.Clamp01(1f - dist / 0.65f) * 0.25f;

                byte alpha = (byte)(Mathf.Clamp01(Mathf.Max(outerRing, innerRing, fill)) * 255f);
                pixels[y * size + x] = new Color32(255, 255, 255, alpha);
            }
        }
        tex.SetPixels32(pixels);
        tex.Apply();
        return Sprite.Create(tex, new Rect(0, 0, size, size), new Vector2(0.5f, 0.5f), 100);
    }

    void OnDestroy()
    {
        if (isActive && statusUI != null)
            statusUI.pauseDepletion = false;
    }
}

using UnityEngine;

[RequireComponent(typeof(Rigidbody2D))]
public class PlayerController : MonoBehaviour
{
    [Header("Movement")]
    public float moveSpeed = 8f;
    public float jumpForce = 18f;

    [Header("Ground Check")]
    public float groundCheckDistance = 0.15f;
    public LayerMask groundLayer = ~0;

    [Header("Respawn")]
    public Vector3 startPosition = new Vector3(1f, 1f, 0f);
    public float deathY = -4f;

    [Header("Potion")]
    public int maxPotions = 3;
    public float sugarDrainPerUse = 15f;

    private int potionCount;
    private Rigidbody2D rb;
    private Animator animator;
    private SpriteRenderer spriteRenderer;
    private Collider2D selfCollider;
    private bool isGrounded;
    private float moveInput;
    private bool jumpRequested;
    private StatusUI statusUI;
    [HideInInspector] public bool controlsReversed;

    static readonly int HashSpeed = Animator.StringToHash("Speed");
    static readonly int HashJump = Animator.StringToHash("Jump");

    void Awake()
    {
        rb = GetComponent<Rigidbody2D>();
        animator = GetComponent<Animator>();
        spriteRenderer = GetComponent<SpriteRenderer>();
        selfCollider = GetComponent<Collider2D>();
        statusUI = FindObjectOfType<StatusUI>();
    }

    void Start()
    {
        startPosition = transform.position;
    }

    void Update()
    {
        if (transform.position.y < deathY)
        {
            Respawn();
            return;
        }

        moveInput = 0f;
        if (Input.GetKey(KeyCode.LeftArrow) || Input.GetKey(KeyCode.A))
            moveInput = controlsReversed ? 1f : -1f;
        if (Input.GetKey(KeyCode.RightArrow) || Input.GetKey(KeyCode.D))
            moveInput = controlsReversed ? -1f : 1f;

        if (moveInput != 0f)
            spriteRenderer.flipX = moveInput > 0f;

        if ((Input.GetKeyDown(KeyCode.UpArrow) || Input.GetKeyDown(KeyCode.W) || Input.GetKeyDown(KeyCode.Space)) && isGrounded)
            jumpRequested = true;

        if (Input.GetKeyDown(KeyCode.Q) && potionCount > 0 && statusUI != null)
        {
            statusUI.AddSugar(-sugarDrainPerUse);
            potionCount--;
            statusUI.UpdatePotionUI(potionCount);
        }

        animator.SetFloat(HashSpeed, Mathf.Abs(moveInput));
    }

    void FixedUpdate()
    {
        isGrounded = false;

        Bounds bounds = selfCollider.bounds;
        selfCollider.enabled = false;
        Vector2 boxCenter = new Vector2(bounds.center.x, bounds.min.y - groundCheckDistance * 0.5f);
        Vector2 boxSize = new Vector2(bounds.size.x * 0.9f, groundCheckDistance);
        isGrounded = Physics2D.OverlapBox(boxCenter, boxSize, 0f, groundLayer) != null;
        selfCollider.enabled = true;

        rb.velocity = new Vector2(moveInput * moveSpeed, rb.velocity.y);

        if (jumpRequested && isGrounded)
        {
            rb.velocity = new Vector2(rb.velocity.x, jumpForce);
            animator.SetTrigger(HashJump);
            jumpRequested = false;
        }
    }

    public bool AddPotion()
    {
        if (potionCount >= maxPotions) return false;
        potionCount++;
        if (statusUI != null) statusUI.UpdatePotionUI(potionCount);
        return true;
    }

    public void Respawn()
    {
        rb.velocity = Vector2.zero;
        transform.position = startPosition;

        potionCount = 0;
        controlsReversed = false;
        var status = FindObjectOfType<StatusUI>();
        if (status != null)
        {
            status.ResetStatus();
            status.UpdatePotionUI(0);
        }

        // Reactivate all picked-up items
        foreach (var food in FindObjectsOfType<FoodItem>(true))
            food.gameObject.SetActive(true);
        foreach (var potion in FindObjectsOfType<PotionItem>(true))
            potion.gameObject.SetActive(true);
    }
}

