using UnityEngine;

public class SugarStateVisual : MonoBehaviour
{
    [Header("Sugar Thresholds")]
    public float highSugarThreshold = 70f;
    public float lowSugarThreshold = 20f;

    [Header("High Sugar Aura")]
    public Color highSugarAuraColor = new Color(1f, 0.35f, 0f, 0.6f);
    public float highSugarAuraScale = 3.0f;
    public float highSugarPulseSpeed = 2f;

    [Header("Low Sugar Aura")]
    public Color lowSugarAuraColor = new Color(0.2f, 0.4f, 1f, 0.6f);
    public float lowSugarAuraScale = 3.2f;
    public float lowSugarPulseSpeed = 6f;

    [Header("Sprite Tint")]
    public Color highSugarTint = new Color(1f, 0.8f, 0.6f, 1f);
    public Color lowSugarTint = new Color(0.6f, 0.75f, 1f, 1f);
    public float tintLerpSpeed = 5f;

    private StatusUI statusUI;
    private Animator animator;
    private SpriteRenderer spriteRenderer;
    private GameObject highSugarAura;
    private GameObject lowSugarAura;
    private Color originalColor;
    private int currentSugarState = 0;
    private Vector3 auraScaleCompensation = Vector3.one;

    static readonly int HashSugarState = Animator.StringToHash("SugarState");

    void Start()
    {
        statusUI = FindObjectOfType<StatusUI>();
        animator = GetComponent<Animator>();
        spriteRenderer = GetComponent<SpriteRenderer>();

        if (spriteRenderer != null)
            originalColor = spriteRenderer.color;

        // Compensate for parent scale so aura has consistent world-space size
        Vector3 parentScale = transform.lossyScale;
        auraScaleCompensation = new Vector3(
            Mathf.Abs(parentScale.x) > 0.001f ? 1f / parentScale.x : 1f,
            Mathf.Abs(parentScale.y) > 0.001f ? 1f / parentScale.y : 1f,
            Mathf.Abs(parentScale.z) > 0.001f ? 1f / parentScale.z : 1f
        );

        CreateAuraObjects();
    }

    void CreateAuraObjects()
    {
        highSugarAura = CreateAuraObject("HighSugarAura", highSugarAuraColor, highSugarAuraScale);
        lowSugarAura = CreateAuraObject("LowSugarAura", lowSugarAuraColor, lowSugarAuraScale);
    }

    GameObject CreateAuraObject(string auraName, Color color, float scale)
    {
        var go = new GameObject(auraName);
        go.transform.SetParent(transform, false);
        go.transform.localPosition = Vector3.zero;
        go.transform.localScale = Vector3.Scale(Vector3.one * scale, auraScaleCompensation);

        var sr = go.AddComponent<SpriteRenderer>();
        sr.sprite = GenerateGlowSprite();
        sr.color = color;
        sr.sortingOrder = 10;
        go.SetActive(false);
        return go;
    }

    void Update()
    {
        if (statusUI == null)
            statusUI = FindObjectOfType<StatusUI>();
        if (statusUI == null) return;

        float sugar = statusUI.sugar;
        int newState = 0;

        if (sugar > highSugarThreshold)
            newState = 1;
        else if (sugar < lowSugarThreshold)
            newState = 2;

        if (animator != null && newState != currentSugarState)
        {
            animator.SetInteger(HashSugarState, newState);
            currentSugarState = newState;
        }

        UpdateAuraActiveState(newState);
    }

    void UpdateAuraActiveState(int sugarState)
    {
        bool highActive = sugarState == 1;
        bool lowActive = sugarState == 2;

        if (highSugarAura != null && highSugarAura.activeSelf != highActive)
            highSugarAura.SetActive(highActive);

        if (lowSugarAura != null && lowSugarAura.activeSelf != lowActive)
            lowSugarAura.SetActive(lowActive);
    }

    void LateUpdate()
    {
        // Smooth sprite color transition
        if (spriteRenderer != null)
        {
            Color targetColor = originalColor;
            if (currentSugarState == 1)
                targetColor = highSugarTint;
            else if (currentSugarState == 2)
                targetColor = lowSugarTint;

            spriteRenderer.color = Color.Lerp(spriteRenderer.color, targetColor, Time.deltaTime * tintLerpSpeed);
        }

        // Aura pulsing (compensated for parent scale)
        if (highSugarAura != null && highSugarAura.activeSelf)
        {
            float pulse = Mathf.Sin(Time.time * highSugarPulseSpeed) * 0.12f + 1f;
            highSugarAura.transform.localScale = Vector3.Scale(Vector3.one * highSugarAuraScale * pulse, auraScaleCompensation);
        }

        if (lowSugarAura != null && lowSugarAura.activeSelf)
        {
            float pulse = Mathf.Sin(Time.time * lowSugarPulseSpeed) * 0.18f + 1f;
            lowSugarAura.transform.localScale = Vector3.Scale(Vector3.one * lowSugarAuraScale * pulse, auraScaleCompensation);
        }
    }

    Sprite GenerateGlowSprite()
    {
        int size = 128;
        var tex = new Texture2D(size, size, TextureFormat.RGBA32, false);
        float half = size * 0.5f;
        Color32[] pixels = new Color32[size * size];

        for (int y = 0; y < size; y++)
        {
            for (int x = 0; x < size; x++)
            {
                float dx = (x - half) / half;
                float dy = (y - half) / half;
                float dist = Mathf.Sqrt(dx * dx + dy * dy);

                // Soft radial glow
                float glow = Mathf.Clamp01(1f - dist / 0.9f);
                glow = Mathf.Pow(glow, 1.5f);

                byte alpha = (byte)(glow * 255f);
                pixels[y * size + x] = new Color32(255, 255, 255, alpha);
            }
        }

        tex.SetPixels32(pixels);
        tex.Apply();
        return Sprite.Create(tex, new Rect(0, 0, size, size), new Vector2(0.5f, 0.5f), 100);
    }

    void OnDestroy()
    {
        if (highSugarAura != null) Destroy(highSugarAura);
        if (lowSugarAura != null) Destroy(lowSugarAura);
    }
}

using System.Collections;
using UnityEngine;
using UnityEngine.Video;

[RequireComponent(typeof(VideoPlayer))]
public class VideoBackground : MonoBehaviour
{
    public string videoFileName = "大肠内部.mp4";
    public Color fallbackColor = new Color(0.5f, 0.7f, 1f);
    VideoPlayer vp;
    RenderTexture rt;
    GameObject quad;
    Material mat;

    void Awake()
    {
        var cam = GetComponent<Camera>();
        vp = GetComponent<VideoPlayer>();
        vp.playOnAwake = false;
        vp.isLooping = true;
        vp.renderMode = VideoRenderMode.RenderTexture;

        if (vp.clip == null && string.IsNullOrEmpty(vp.url))
        {
            vp.source = VideoSource.Url;
            vp.url = Application.dataPath + "/" + videoFileName;
        }

        rt = new RenderTexture(1920, 1080, 0, RenderTextureFormat.ARGB32);
        rt.Create();
        vp.targetTexture = rt;

        // Quad with fallback color (video will replace it when ready)
        quad = GameObject.CreatePrimitive(PrimitiveType.Quad);
        quad.name = "VideoBackgroundQuad";
        Destroy(quad.GetComponent<Collider>());
        quad.transform.SetParent(transform, false);
        quad.transform.localPosition = new Vector3(0, 0, cam.farClipPlane * 0.99f);

        // 1x1 texture with fallback color for when video is off
        var fallbackTex = new Texture2D(1, 1);
        fallbackTex.SetPixel(0, 0, fallbackColor);
        fallbackTex.Apply();

        mat = new Material(Shader.Find("Unlit/Texture"));
        mat.mainTexture = fallbackTex;
        quad.GetComponent<Renderer>().material = mat;

        SizeQuadToView();
        StartCoroutine(SizeQuadDelayed());

        vp.prepareCompleted += OnPrepared;
        vp.Prepare();
    }

    IEnumerator SizeQuadDelayed()
    {
        // Retry sizing after CameraFollow adjusts ortho size
        yield return new WaitForEndOfFrame();
        SizeQuadToView();
    }

    void SizeQuadToView()
    {
        var cam = GetComponent<Camera>();
        if (cam == null || quad == null) return;

        float h = cam.orthographicSize * 2f;
        float w = h * (16f / 9f);
        quad.transform.localScale = new Vector3(w, h, 1);
    }

    void LateUpdate()
    {
        SizeQuadToView();
    }

    void OnPrepared(VideoPlayer source)
    {
        source.prepareCompleted -= OnPrepared;
        mat.mainTexture = rt;
        source.Play();
    }

    void OnDestroy()
    {
        if (rt != null)
            rt.Release();
    }
}

using UnityEngine;

public class TrophyItem : MonoBehaviour
{
    void Awake()
    {
        if (GetComponent<Collider2D>() == null)
        {
            BoxCollider2D col = gameObject.AddComponent<BoxCollider2D>();
            col.isTrigger = true;
            col.size = new Vector2(2f, 2f);
        }
    }

    void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player"))
            return;

        StatusUI status = FindObjectOfType<StatusUI>();
        if (status != null)
            status.ShowVictory();
    }
}

using UnityEngine;
using UnityEngine.UI;
using TMPro;

public class StatusUI : MonoBehaviour
{
    [Header("Bars")]
    public Image hungerFill;
    public Image sugarFill;

    [Header("Value Texts")]
    public TMP_Text hungerValueText;
    public TMP_Text sugarValueText;

    [Header("Values")]
    [Range(0, 100)] public float hunger = 100f;
    [Range(0, 100)] public float sugar = 100f;

    [Header("Potion UI")]
    public TMP_Text potionText;

    [Header("Victory")]
    public GameObject victoryPanel;
    public TMP_Text victoryText;

    [Header("Depletion Rate (per second)")]
    public float hungerRate = 2f;
    public float sugarRate = 1.5f;

    [Header("Max Values")]
    public float maxHunger = 100f;
    public float maxSugar = 100f;

    private bool isDead;
    [HideInInspector] public bool pauseDepletion;

    void Start()
    {
        sugar = 70f;
        hunger = 80f;
        UpdateStatusUI();
    }

    void Update()
    {
        if (isDead) return;

        if (!pauseDepletion)
        {
            hunger = Mathf.Clamp(hunger - hungerRate * Time.deltaTime, 0f, maxHunger);
            sugar = Mathf.Clamp(sugar - sugarRate * Time.deltaTime, 0f, maxSugar);
        }
        UpdateStatusUI();

        if (hunger <= 0f || sugar <= 0f)
        {
            isDead = true;
            var pc = FindObjectOfType<PlayerController>();
            if (pc != null) pc.Respawn();
        }
    }

    private void UpdateStatusUI()
    {
        if (hungerFill != null)
        {
            hungerFill.type = Image.Type.Filled;
            hungerFill.fillMethod = Image.FillMethod.Horizontal;
            hungerFill.fillOrigin = (int)Image.OriginHorizontal.Left;
            hungerFill.fillAmount = hunger / maxHunger;
        }

        if (sugarFill != null)
        {
            sugarFill.type = Image.Type.Filled;
            sugarFill.fillMethod = Image.FillMethod.Horizontal;
            sugarFill.fillOrigin = (int)Image.OriginHorizontal.Left;
            sugarFill.fillAmount = sugar / maxSugar;
        }

        if (hungerValueText != null)
            hungerValueText.text = Mathf.RoundToInt(hunger).ToString();

        if (sugarValueText != null)
            sugarValueText.text = Mathf.RoundToInt(sugar).ToString();
    }

    public void UpdatePotionUI(int count)
    {
        if (potionText != null)
            potionText.text = $" X {count}";
    }

    public void ResetStatus()
    {
        hunger = maxHunger;
        sugar = 70f;
        hunger = 80f; //重生后的数值
        isDead = false;
        UpdateStatusUI();
    }

    public void AddSugar(float amount)
    {
        sugar = Mathf.Clamp(sugar + amount, 0f, maxSugar);
    }

    public void AddHunger(float amount)
    {
        hunger = Mathf.Clamp(hunger + amount, 0f, maxHunger);
    }

    public void ShowVictory()
    {
        if (victoryPanel != null)
        {
            victoryPanel.SetActive(true);
            if (victoryText != null)
                victoryText.text = "恭喜通关！";
            return;
        }

        var canvas = FindObjectOfType<Canvas>();
        if (canvas == null) return;

        var go = new GameObject("VictoryPanel", typeof(RectTransform), typeof(Image));
        go.transform.SetParent(canvas.transform, false);
        var rt = go.GetComponent<RectTransform>();
        rt.anchorMin = Vector2.zero;
        rt.anchorMax = Vector2.one;
        rt.sizeDelta = Vector2.zero;
        go.GetComponent<Image>().color = new Color(0, 0, 0, 0.6f);

        var textGo = new GameObject("VictoryText", typeof(RectTransform), typeof(TextMeshProUGUI));
        textGo.transform.SetParent(go.transform, false);
        var trt = textGo.GetComponent<RectTransform>();
        trt.anchorMin = Vector2.zero;
        trt.anchorMax = Vector2.one;
        trt.sizeDelta = Vector2.zero;
        var tmp = textGo.GetComponent<TextMeshProUGUI>();
        tmp.text = "恭喜通关！";
        tmp.fontSize = 48;
        tmp.alignment = TextAlignmentOptions.Center;
        tmp.color = Color.yellow;
    }
}

using System.Collections;
using UnityEngine;
using UnityEngine.UI;

public class StatusEffect : MonoBehaviour
{
    [Header("Stamina Effect")]
    [Tooltip("hunger 10~20: speed 0.8, jump 0.8")]
    public float lowStaminaSpeed = 0.8f;
    public float lowStaminaJump = 0.8f;
    [Tooltip("hunger > 80: speed 0.5, jump 0.5")]
    public float highStaminaSpeed = 0.5f;
    public float highStaminaJump = 0.5f;

    [Header("Near Death (hunger < 10)")]
    [Tooltip("Adrenaline surge: speed 1.5, jump 1.5")]
    public float nearDeathSpeed = 1.5f;
    public float nearDeathJump = 1.5f;

    [Header("High Sugar Effect (> 70)")]
    public float highSugarSpeedMultiplier = 0.85f;
    public float highSugarHpDrain = 1f;
    public float highSugarJumpMultiplier = 0.75f;
    public float highSugarDrainInterval = 2f;

    [Header("Screen Flash & Shake")]
    public Color flashColor = new Color(1f, 0f, 0f, 0.3f);
    public float flashDuration = 1.2f;
    public float shakeIntensity = 0.15f;
    public float shakeFrequency = 0.05f;

    private StatusUI statusUI;
    private PlayerController playerController;
    private CameraFollow cameraFollow;
    private Image flashOverlay;
    private float highSugarTimer;
    private float originalMoveSpeed;
    private float originalJumpForce;
    private Canvas canvas;
    private Coroutine flashRoutine;
    private Coroutine shakeRoutine;

    void Start()
    {
        statusUI = FindObjectOfType<StatusUI>();
        playerController = GetComponent<PlayerController>();
        canvas = FindObjectOfType<Canvas>();
        cameraFollow = FindObjectOfType<CameraFollow>();

        if (playerController != null)
        {
            originalMoveSpeed = playerController.moveSpeed;
            originalJumpForce = playerController.jumpForce;
        }
    }

    void Update()
    {
        if (statusUI == null || playerController == null) return;

        float hunger = statusUI.hunger;
        float sugar = statusUI.sugar;

        float speedMult = 1f;
        float jumpMult = 1f;

        // --- Hunger-based speed/jump modifiers ---
        if (hunger < 10f)
        {
            speedMult *= nearDeathSpeed;
            jumpMult *= nearDeathJump;
        }
        else if (hunger < 20f)
        {
            speedMult *= lowStaminaSpeed;
            jumpMult *= lowStaminaJump;
        }
        else if (hunger > 80f)
        {
            speedMult *= highStaminaSpeed;
            jumpMult *= highStaminaJump;
        }

        bool lowHunger = hunger < 20f;
        bool lowSugar = sugar < 20f;
        bool shouldFlash = lowHunger || lowSugar;

        // --- Low sugar effect: reverse controls ---
        playerController.controlsReversed = lowSugar;

        // --- Screen flash (hunger < 20 or sugar < 20) ---
        if (shouldFlash)
        {
            if (flashOverlay == null && canvas != null)
                CreateFlashOverlay();

            if (flashRoutine == null && flashOverlay != null)
                flashRoutine = StartCoroutine(FlashLoop());
        }
        else
        {
            if (flashRoutine != null)
            {
                StopCoroutine(flashRoutine);
                flashRoutine = null;
            }

            if (flashOverlay != null && flashOverlay.gameObject.activeSelf)
                flashOverlay.gameObject.SetActive(false);
        }

        // --- Screen shake (hunger < 20) ---
        if (lowHunger)
        {
            if (shakeRoutine == null && cameraFollow != null)
                shakeRoutine = StartCoroutine(ShakeLoop());
        }
        else
        {
            if (shakeRoutine != null)
            {
                StopCoroutine(shakeRoutine);
                shakeRoutine = null;
            }
            if (cameraFollow != null)
                cameraFollow.shakeOffset = Vector3.zero;
        }

        // --- High sugar effect: sugar > 70 ---
        if (sugar > 70f)
        {
            speedMult *= highSugarSpeedMultiplier;
            jumpMult *= highSugarJumpMultiplier;

            highSugarTimer += Time.deltaTime;
            if (highSugarTimer >= highSugarDrainInterval)
            {
                highSugarTimer = 0f;
                statusUI.AddHunger(-highSugarHpDrain);
            }
        }
        else
        {
            highSugarTimer = 0f;
        }

        playerController.moveSpeed = originalMoveSpeed * speedMult;
        playerController.jumpForce = originalJumpForce * jumpMult;
    }

    private void CreateFlashOverlay()
    {
        var go = new GameObject("LowSugarFlash", typeof(RectTransform), typeof(Image));
        go.transform.SetParent(canvas.transform, false);
        var rt = go.GetComponent<RectTransform>();
        rt.anchorMin = Vector2.zero;
        rt.anchorMax = Vector2.one;
        rt.sizeDelta = Vector2.zero;
        go.transform.SetAsLastSibling();

        flashOverlay = go.GetComponent<Image>();
        flashOverlay.color = flashColor;
        flashOverlay.raycastTarget = false;
        flashOverlay.gameObject.SetActive(false);
    }

    private IEnumerator FlashLoop()
    {
        while (true)
        {
            flashOverlay.gameObject.SetActive(true);
            yield return new WaitForSeconds(flashDuration);
            flashOverlay.gameObject.SetActive(false);
            yield return new WaitForSeconds(flashDuration);
        }
    }

    private IEnumerator ShakeLoop()
    {
        while (true)
        {
            cameraFollow.shakeOffset = (Vector3)Random.insideUnitCircle * shakeIntensity;
            yield return new WaitForSeconds(shakeFrequency);
        }
    }

    void OnDestroy()
    {
        if (flashRoutine != null)
        {
            StopCoroutine(flashRoutine);
            flashRoutine = null;
        }
        if (shakeRoutine != null)
        {
            StopCoroutine(shakeRoutine);
            shakeRoutine = null;
        }
    }
}

