using UnityEngine;

public class CameraFollow : MonoBehaviour
{
    public Transform target;
    public float smoothSpeed = 6f;
    public float zoomSpeed = 4f;

    [Header("Framing")]
    public float groundY = 0f;
    public float minOrthoSize = 6f;
    public float maxOrthoSize = 18f;
    public float zoomPerUnitHeight = 0.45f;

    private Camera cam;
    [HideInInspector] public Vector3 shakeOffset;

    void Awake()
    {
        cam = GetComponent<Camera>();
    }

    void LateUpdate()
    {
        if (target == null || cam == null) return;

        float playerY = target.position.y;
        float playerHeight = Mathf.Max(0f, playerY - groundY);

        // Camera looks at midpoint between ground and player
        float lookY = (playerY + groundY) * 0.5f;

        // Ortho size grows with player height to keep both in frame
        float targetSize = Mathf.Clamp(
            minOrthoSize + playerHeight * zoomPerUnitHeight,
            minOrthoSize,
            maxOrthoSize
        );

        cam.orthographicSize = Mathf.Lerp(cam.orthographicSize, targetSize, zoomSpeed * Time.deltaTime);

        float targetX = target.position.x;
        Vector3 desiredPos = new Vector3(targetX, lookY, -10f);
        transform.position = Vector3.Lerp(transform.position, desiredPos, smoothSpeed * Time.deltaTime);
        transform.position += shakeOffset;
    }
}

using UnityEngine;

[RequireComponent(typeof(SpriteRenderer))]
public class AcidFlow : MonoBehaviour
{
    [Header("Flow")]
    public float speed = 0.3f;

    [Header("Wave")]
    public float waveAmount = 0.3f;
    public float waveSpeed = 2f;
    public float waveFrequency = 3f;
    [Range(4, 100)] public int segments = 30;

    private Mesh mesh;
    private Vector3[] baseVerts;
    private float offset;

    void Start()
    {
        BuildWaveMesh();
    }

    void BuildWaveMesh()
    {
        var sr = GetComponent<SpriteRenderer>();
        if (sr == null || sr.sprite == null) return;

        float w = sr.sprite.bounds.size.x;
        float h = sr.sprite.bounds.size.y;

        int count = segments + 1;
        baseVerts = new Vector3[count * 2];
        Vector3[] verts = new Vector3[count * 2];
        Vector2[] uv = new Vector2[count * 2];
        int[] tris = new int[segments * 6];

        float segW = w / segments;

        for (int i = 0; i < count; i++)
        {
            float t = (float)i / segments;
            float x = -w / 2f + i * segW;
            float bottom = -h / 2f;
            float top = h / 2f;

            baseVerts[i * 2] = new Vector3(x, bottom, 0);
            baseVerts[i * 2 + 1] = new Vector3(x, top, 0);
            verts[i * 2] = baseVerts[i * 2];
            verts[i * 2 + 1] = baseVerts[i * 2 + 1];
            uv[i * 2] = new Vector2(t, 0);
            uv[i * 2 + 1] = new Vector2(t, 1);
        }

        for (int i = 0; i < segments; i++)
        {
            int a = i * 2;
            int b = a + 1;
            int c = a + 2;
            int d = a + 3;

            tris[i * 6] = a;
            tris[i * 6 + 1] = c;
            tris[i * 6 + 2] = b;
            tris[i * 6 + 3] = b;
            tris[i * 6 + 4] = c;
            tris[i * 6 + 5] = d;
        }

        mesh = new Mesh();
        mesh.vertices = verts;
        mesh.uv = uv;
        mesh.triangles = tris;

        // Replace SpriteRenderer with MeshFilter + MeshRenderer
        var mf = gameObject.AddComponent<MeshFilter>();
        var mr = gameObject.AddComponent<MeshRenderer>();
        mr.material = sr.material;
        Destroy(sr);
    }

    void Update()
    {
        if (mesh == null || baseVerts == null) return;

        offset += Time.deltaTime * speed;
        int count = segments + 1;
        var verts = mesh.vertices;

        for (int i = 0; i < count; i++)
        {
            float t = (float)i / segments;
            float wave = Mathf.Sin(t * waveFrequency * Mathf.PI * 2 + Time.time * waveSpeed + offset) * waveAmount;

            // Bottom stays fixed
            verts[i * 2] = baseVerts[i * 2];
            // Top waves
            verts[i * 2 + 1] = baseVerts[i * 2 + 1] + new Vector3(0, wave, 0);
        }

        mesh.vertices = verts;
        mesh.RecalculateNormals();
    }
}

using UnityEngine;
using UnityEditor;
using System.IO;

public class FoodBaker
{
    [MenuItem("Tools/Bake Food Prefabs", false, 1)]
    static void Bake()
    {
        string folder = "Assets/Prefabs/Mg3D_Food";
        string[] fbxs = Directory.GetFiles(folder, "*.fbx");
        int count = 0;

        foreach (string fbx in fbxs)
        {
            string name = Path.GetFileNameWithoutExtension(fbx);
            string modelPath = Path.Combine(folder, name + ".fbx").Replace("\\", "/");
            string prefabPath = Path.Combine(folder, name + ".prefab").Replace("\\", "/");

            if (File.Exists(prefabPath))
            {
                // Assign stats to existing prefab
                GameObject existing = AssetDatabase.LoadAssetAtPath<GameObject>(prefabPath);
                if (existing != null)
                {
                    FoodItem food = existing.GetComponent<FoodItem>();
                    if (food != null) AssignStats(name, food);
                }
                continue;
            }

            GameObject model = AssetDatabase.LoadAssetAtPath<GameObject>(modelPath);
            if (model == null) continue;

            GameObject instance = (GameObject)PrefabUtility.InstantiatePrefab(model);
            instance.name = name;
            instance.transform.localScale = Vector3.one * 0.5f;

            BoxCollider2D col = instance.AddComponent<BoxCollider2D>();
            col.isTrigger = true;
            col.size = new Vector2(1f, 1f);

            FoodItem foodComp = instance.AddComponent<FoodItem>();
            AssignStats(name, foodComp);

            PrefabUtility.SaveAsPrefabAsset(instance, prefabPath);
            Object.DestroyImmediate(instance);
            count++;
        }

        AssetDatabase.Refresh();
        Debug.Log($"Done! Created {count} food prefabs.");
    }

    static void AssignStats(string name, FoodItem food)
    {
        switch (name)
        {
            case "Hamburger":  food.sugarBonus = 15f; food.hungerBonus = 20f; break;
            case "Hotdog":     food.sugarBonus = 10f; food.hungerBonus = 15f; break;
            case "Cheese":     food.sugarBonus = 5f;  food.hungerBonus = 10f; break;
            case "Banana":     food.sugarBonus = 8f;  food.hungerBonus = 5f;  break;
            case "Cherry":     food.sugarBonus = 3f;  food.hungerBonus = 2f;  break;
            case "Olive":      food.sugarBonus = 2f;  food.hungerBonus = 1f;  break;
            case "Watermelon": food.sugarBonus = 5f;  food.hungerBonus = 8f;  break;
        }
    }
}

